"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([["985"],{5256(e,o,t){t.r(o),t.d(o,{metadata:()=>n,default:()=>u,frontMatter:()=>r,contentTitle:()=>i,toc:()=>l,assets:()=>c});var n=JSON.parse('{"id":"faculty/schoology/student-centered-courses","title":"Student Centered Courses","description":"Getting Started with Schoology","source":"@site/docs/faculty/schoology/student-centered-courses.mdx","sourceDirName":"faculty/schoology","slug":"/faculty/schoology/student-centered-courses","permalink":"/faculty/schoology/student-centered-courses","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"title":"Student Centered Courses"},"sidebar":"defaultSidebar","previous":{"title":"Saving to Resources","permalink":"/faculty/schoology/saving-to-resources"},"next":{"title":"Working in Resources","permalink":"/faculty/schoology/working-in-resources"}}'),s=t(4848),a=t(8453);let r={title:"Student Centered Courses"},i,c={},l=[{value:"Getting Started with Schoology",id:"getting-started-with-schoology",level:2},{value:"UPrep Community Expectations for Schoology",id:"uprep-community-expectations-for-schoology",level:2},{value:"Upload a Syllabus",id:"upload-a-syllabus",level:3},{value:"Post and Date all Assignments",id:"post-and-date-all-assignments",level:3}];function d(e){let o={em:"em",h2:"h2",h3:"h3",p:"p",...(0,a.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(o.h2,{id:"getting-started-with-schoology",children:"Getting Started with Schoology"}),"\n",(0,s.jsx)(o.p,{children:"At U Prep, we use Schoology in myriad ways to facilitate a dynamic and extended\nlearning environment. Each class has a corresponding Schoology course site which\nis created for you at the beginning of the year (if your courses do not match\nwhat you expect to see, contact June). Schoology has a variety of powerful\ncommunication, organization and learning tools, and each course at UPrep uses\nthese tools in different ways which match our faculty's overall course design\nand goals. School-wide, though, there are a few universal expectations and some\ncommon practices that we've developed. Please consider this an overview of the\nSchoology essentials, and explore the resources below to learn more about\nSchoology."}),"\n",(0,s.jsx)(o.h2,{id:"uprep-community-expectations-for-schoology",children:"UPrep Community Expectations for Schoology"}),"\n",(0,s.jsx)(o.h3,{id:"upload-a-syllabus",children:"Upload a Syllabus"}),"\n",(0,s.jsx)(o.p,{children:"Please upload your course syllabus to Schoology and place it in an easily\naccessible location. You can create it in Schoology as a Page, or create it on\nyour computer or iPad in a word processor such as Word or Pages and upload as a\nPDF or DOC."}),"\n",(0,s.jsx)(o.h3,{id:"post-and-date-all-assignments",children:"Post and Date all Assignments"}),"\n",(0,s.jsx)(o.p,{children:"Students rely on Schoology as their primary resource for their upcoming due\ndates and homework obligations. In order to support their responsibility and\norganization, please create an entry in Schoology for any due-date student\nexpectations, even if you plan on collecting the work physically or off-line.\nYou can create the following types of materials for classwork and give them a\ndue date which will be visible to students:"}),"\n",(0,s.jsx)(o.p,{children:"Assignments - The most flexible and commonly used type of Schoology material at\nU Prep. You can attach files, a written description, or a link. By default,\nstudents will be able to submit a file back to you through an assignment."}),"\n",(0,s.jsx)(o.p,{children:(0,s.jsx)(o.em,{children:"A suggestion: If you don't want students to submit this electronically (for\nexample, there's a handout or worksheet), turn off \"Enable Submissions\" (see 4:\nAdvanced Settings). This helps students avoid confusion about how to submit the\nassignment."})}),"\n",(0,s.jsx)(o.p,{children:"Discussions - Discussions allow students to see each others' submissions.\nStudents can type responses directly into a discussion, or attach any kind of\nfile. This is commonly used for peer-review assignments, where you want students\nto be able to see and comment upon each others' work. Discussions can be graded\nor ungraded, and can be given a due date."}),"\n",(0,s.jsx)(o.p,{children:"Events - Events are dated entries on the course calendar. These are commonly\nused for guest speakers or field trips, project benchmarks where nothing is\nsubmitted, or marking a test date. Events can have a written description or file\nattachments."}),"\n",(0,s.jsx)(o.p,{children:"Quiz/Test - You can give quizzes or tests directly in Schoology. These are often\nused as formative checks since they can be assigned to a specific date/time, or\nleft open with a due date, and you can control how many opportunities students\nhave. You can also control options such as how students are graded, whether\nquestions are randomized, and what kind of feedback students get on their\nperformance."}),"\n",(0,s.jsx)(o.p,{children:"A suggestion: Since students consult Schoology as a way to plan their homework\nfor the evening, consider when you post new homework into Schoology. Students\ntell us, for example, that it's most useful when the homework is posted during\nclass or immediately after school, even if it's been discussed in class. Posting\nhomework late at night for the next day may miss students if they've already\ncompleted their home study time for the day."}),"\n",(0,s.jsx)(o.p,{children:"Some Common Practices and Suggestions"}),"\n",(0,s.jsx)(o.p,{children:"The following are some general suggested practices based on our experience using\nSchoology."}),"\n",(0,s.jsx)(o.p,{children:"Organize the Course by Unit, Project or Topic. Using folders to organize the\ncourse by unit or topic can help students find both the currently active\nresources and past activities or resources that they may wish to revisit."}),"\n",(0,s.jsx)(o.p,{children:"Running Conversations in the Updates Thread. The Updates section is a running\nchronological conversation, similar to Facebook. Students can post in here as\nwell. It's a common resource for students to ask questions of each other, or to\nshare files or resources, as well as for you to ask questions or share\ninformation separate from an assignment or specific class activity."}),"\n",(0,s.jsx)(o.p,{children:"Schoology Gradebook. While you can use whatever grade-keeping system you prefer\nin your courses, many students have shared that they get great benefit from\nteachers using the Gradebook feature of Schoology. Whenever you create an\nassignment or other graded activity (quiz, discussion), it is automatically\nentered into your course gradebook. Again, you are not required to give your\nfeedback or scores in Schoology, but use of this resource has grown each term as\na feedback and communication tool."}),"\n",(0,s.jsx)(o.p,{children:"These guidelines were developed a few years ago to help educators create easy to\nuse courses for students:"}),"\n",(0,s.jsx)("div",{style:{textAlign:"center",margin:"2rem 0"},children:(0,s.jsx)("iframe",{src:"https://drive.google.com/file/d/1YSWwOAlVGzWxjhaXeYHI2aAGBEXLl0hB/preview",width:"100%",height:"800px",frameBorder:"0",allowFullScreen:!0})})]})}function u(e={}){let{wrapper:o}={...(0,a.R)(),...e.components};return o?(0,s.jsx)(o,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},8453(e,o,t){t.d(o,{R:()=>r,x:()=>i});var n=t(6540);let s={},a=n.createContext(s);function r(e){let o=n.useContext(a);return n.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function i(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:r(e.components),n.createElement(a.Provider,{value:o},e.children)}}}]);